"""
VWAP Bounce Test Fixtures
=========================

Each fixture tests ONE specific rule at its boundary.
All fixtures include OHLCV + VWAP data (VWAP is required for VwapBounce).
All fixtures have 16+ bars (min_bars_required=15).

Uses _make_bars_with_vwap() which returns (DataFrame, VWAP Series).
"""

import pandas as pd
from datetime import datetime, timedelta


def _make_bars_with_vwap(data: list, base_hour: int = 10, base_minute: int = 0) -> tuple:
    """Create DataFrame and VWAP series from (O, H, L, C, V, VWAP) tuples.

    Args:
        data: List of (open, high, low, close, volume, vwap) tuples
        base_hour: Starting hour (ET), default 10:00 (avoids 9:30 reset)

    Returns:
        (DataFrame, pd.Series) — bars and VWAP series
    """
    base_time = datetime(2025, 1, 15, base_hour, base_minute)
    rows = []
    vwap_vals = []
    for i, (o, h, l, c, v, vw) in enumerate(data):
        rows.append({
            "timestamp": base_time + timedelta(minutes=i),
            "open": o,
            "high": h,
            "low": l,
            "close": c,
            "volume": v,
        })
        vwap_vals.append(vw)
    df = pd.DataFrame(rows)
    vwap = pd.Series(vwap_vals, name="vwap")
    return df, vwap


